'use server';

import { generateKissVideo, type GenerateKissVideoInput } from '@/ai/flows/generate-kiss-video';

export async function createKissVideoAction(
  input: GenerateKissVideoInput
): Promise<{ videoDataUri?: string; error?: string }> {
  try {
    const result = await generateKissVideo(input);
    if (!result.videoDataUri) {
      return { error: 'The AI failed to return a video. Please try again.' };
    }
    return { videoDataUri: result.videoDataUri };
  } catch (e) {
    console.error('Video generation error:', e);
    const message = e instanceof Error ? e.message : 'An unknown error occurred.';
    
    // Provide more specific user-facing errors
    if (message.includes('quota')) {
        return { error: 'We are experiencing high demand. Please try again later.' };
    }
    if (message.includes('Invalid argument') || message.includes('failed to find the generated video')) {
        return { error: 'The AI could not process the image(s). Please try different photos.' };
    }
    if (message.includes('Video generation failed')) {
        return { error: `AI Error: ${message.replace('Video generation failed: ', '')}` };
    }

    return { error: 'An unexpected error occurred. Please try again later.' };
  }
}
